import{_ as o,o as r,c as e,ai as a}from"./chunks/framework.DMjte4z8.js";const c=JSON.parse('{"title":"从零创建自定义单位：英雄和普通单位","description":"","frontmatter":{"title":"从零创建自定义单位：英雄和普通单位","category":"object-editor","updated":"2026-04-28T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://www.hiveworkshop.com/threads/creating-custom-units.270941/","https://www.thehelper.net/threads/the-basics-of-the-world-editor.33390/","https://www.youtube.com/watch?v=kH0vKi0_WDU"]},"headers":[],"relativePath":"object-editor/从零创建自定义单位英雄和普通单位.md","filePath":"object-editor/从零创建自定义单位英雄和普通单位.md","lastUpdated":1777383225000}'),l={name:"object-editor/从零创建自定义单位英雄和普通单位.md"};function i(n,t,s,u,q,p){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="从零创建自定义单位-英雄和普通单位" tabindex="-1">从零创建自定义单位：英雄和普通单位 <a class="header-anchor" href="#从零创建自定义单位-英雄和普通单位" aria-label="Permalink to “从零创建自定义单位：英雄和普通单位”">​</a></h1><h2 id="什么是自定义单位" tabindex="-1">什么是自定义单位？ <a class="header-anchor" href="#什么是自定义单位" aria-label="Permalink to “什么是自定义单位？”">​</a></h2><p>在本节中，我们将学习什么是自定义单位，以及英雄单位和普通单位之间的基本区别。学完这节后，你将理解为什么RPG地图需要自定义单位，并为后续创建自己的单位打下基础。</p><h3 id="自定义单位在rpg地图中的作用" tabindex="-1">自定义单位在RPG地图中的作用 <a class="header-anchor" href="#自定义单位在rpg地图中的作用" aria-label="Permalink to “自定义单位在RPG地图中的作用”">​</a></h3><p>自定义单位是你在地图编辑器中从零开始创建的角色单位，它们不是游戏默认存在的[^1]。在RPG地图里，每一个你控制的英雄、每一只野外怪物、每一个商店NPC，基本上都是自定义单位。简单来说，<strong>自定义单位就是地图作者根据游戏剧情和玩法需要，专门设计的角色</strong>。通过调整单位的属性数值、外观造型、技能配置，作者可以创造出各种独特的游戏体验。</p><blockquote><p><strong>💡 新手提示</strong>：你可以把自定义单位理解为&quot;捏脸&quot;——不是用画笔，而是用编辑器的各种设置来塑造角色的能力值和外观。</p></blockquote><h3 id="英雄单位与普通单位的区别" tabindex="-1">英雄单位与普通单位的区别 <a class="header-anchor" href="#英雄单位与普通单位的区别" aria-label="Permalink to “英雄单位与普通单位的区别”">​</a></h3><p>在编辑器中，单位分为两大类：<strong>英雄单位（Hero）</strong>和<strong>普通单位（Non-Hero）</strong>。</p><p><strong>英雄单位</strong>是玩家可以控制的特殊角色，它们拥有以下特征：</p><ul><li>每次战斗后可以自动恢复生命值和魔法值</li><li>能够获得经验值并升级变强</li><li>玩家只能同时控制有限数量的英雄（通常为1-6个）</li><li>在编辑器中需要在&quot;单位——英雄&quot;标签页创建[^1]</li></ul><p><strong>普通单位</strong>则是地图中作为敌人、队友或场景装饰的角色。它们可以被批量生成（像刷怪一样），但不会升级，也不会自动回血。野外的小怪、弓箭手、建筑工人都属于普通单位。</p><p>两者的核心区别在于：<strong>英雄是玩家培养成长的对象，普通单位是服务于游戏流程的工具</strong>。</p><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记在创建单位时勾选&quot;是英雄&quot;选项，结果导致单位无法获得经验值升级。解决方法是在单位属性中找到&quot;单位——英雄&quot;选项并勾选。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>现在你已经了解了自定义单位的概念，以及英雄单位和普通单位的基本区别。接下来我们可以开始实际创建一个自定义单位了！</p><h2 id="打开对象编辑器" tabindex="-1">打开对象编辑器 <a class="header-anchor" href="#打开对象编辑器" aria-label="Permalink to “打开对象编辑器”">​</a></h2><p>在本节中，你将学习如何打开对象编辑器（Object Editor），这是创建自定义单位的基础工具。学完本节后，你就能找到并打开这个强大的编辑界面，为下一步创建你的第一个自定义单位做好准备。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：启动世界编辑器</strong> — 首先打开 Warcraft III 或 Warcraft III: Reforged，在主菜单中点击&quot;自定义游戏&quot;（Custom Games），然后在列表中找到并双击&quot;World Editor&quot;（世界编辑器）[^1]。如果你的编辑器启动较慢，请耐心等待，这是正常现象。</p></li><li><p><strong>第二步：找到对象编辑器入口</strong> — 在 World Editor 界面顶部菜单栏中，点击&quot;模块&quot;（Modules）菜单，然后在下拉列表中找到并点击&quot;对象编辑器&quot;（Object Editor）[^3]。你也可以使用快捷键 <strong>F4</strong> 直接打开它——这是老手们最常用的方法！</p></li><li><p><strong>第三步：认识对象编辑器界面</strong> — 打开后，你会看到一个包含多个选项卡的窗口，主要包括：单位（Units）、技能（Abilities）、物品（Items）、科技（Upgrades）等选项卡[^1]。我们需要重点关注&quot;单位&quot;选项卡。</p></li><li><p><strong>第四步：切换到单位选项卡</strong> — 点击&quot;单位&quot;（Units）选项卡，你会看到左侧列出了所有内置单位，右侧则是选中单位的详细属性面板[^2]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你第一次打开对象编辑器，可能会觉得选项密密麻麻、数值很多。不用担心！你不需要修改所有内容，只需关注与自己设计目标相关的属性即可。记住，你随时可以按 F1 查看帮助文档。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手打开编辑器后找不到对象编辑器，这是因为它不在&quot;文件&quot;或&quot;编辑&quot;菜单里——它属于&quot;模块&quot;菜单下的功能。请务必在菜单栏仔细查找 Modules 选项。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够成功打开对象编辑器，并看到包含单位、技能、物品等多个选项卡的界面。现在你已准备好开始创建自定义单位了！在下一节中，我们将学习如何新建一个自定义单位并修改其基本属性。</p><h2 id="创建普通单位" tabindex="-1">创建普通单位 <a class="header-anchor" href="#创建普通单位" aria-label="Permalink to “创建普通单位”">​</a></h2><p>本节我们将学习如何在物编（物体编辑器）中创建自定义普通单位，并为它们设置生命值、攻击力、外观图标等基本属性。学完本节后，你将能独立创造出属于自己的士兵、野怪或任何非英雄单位！</p><h3 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>打开物体编辑器</strong> — 在World Editor顶部菜单栏点击&quot;触发器编辑器&quot;旁边的&quot;物体编辑器&quot;选项[^1]。如果没有看到，可以在菜单&quot;模块&quot;中勾选它。</p></li><li><p><strong>创建新单位</strong> — 在左侧目录中点击&quot;单位&quot;，然后按 <code>Ctrl+Shift+N</code> 快捷键即可快速创建新单位[^1]。你也可以在任意单位上右键，选择&quot;新建自定义单位&quot;。新建后，你会看到右侧出现大量可编辑的属性面板。</p></li><li><p><strong>设置生命值</strong> — 找到&quot;生命值&quot;字段，将其改为你想要的值（如500）。如果想让生命值随等级提升，可以设置&quot;生命值（等级1）&quot;、&quot;生命值（等级2）&quot;等[^2]。</p></li><li><p><strong>设置攻击力</strong> — 找到&quot;Combat - Attack 1 - Damage（战斗-攻击1-伤害）&quot;字段，填入基础伤害值（如25）[^2]。如果想给单位设置两种不同攻击方式，可以展开&quot;Attack 2&quot;并设置第二组伤害数值。</p></li><li><p><strong>设置单位图标</strong> — 展开&quot;Art - Icon - Game Interface&quot;字段，点击右侧按钮选择一张图标[^2]。这是玩家在游戏中选中该单位时看到的图片，也是编队（Ctrl+数字键）时显示的图标。</p></li><li><p><strong>调整单位高度（可选）</strong> — 找到&quot;Movement - Height&quot;字段，数值越大单位越高。如果设为负数，单位会&quot;陷进&quot;地面里[^2]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：创建单位时，建议先从一个现有单位（如&quot;兽人步兵&quot;）上右键选择&quot;复制&quot;，然后在此基础上修改，这样可以省去很多默认设置的时间！</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手忘记给单位设置&quot;名称&quot;字段，导致在游戏中只能看到&quot;(null)&quot;。请务必在&quot;名称&quot;栏填写你想要的单位名字（如&quot;森林狼&quot;）。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能在物编中看到自己创建的自定义单位，并能在&quot;游戏测试&quot;中将其放置到地图上，看到它的图标、生命值和攻击力都已按照你的设置显示了！</p><h2 id="创建英雄单位" tabindex="-1">创建英雄单位 <a class="header-anchor" href="#创建英雄单位" aria-label="Permalink to “创建英雄单位”">​</a></h2><p>在本节中，你将学习如何把一个普通单位变成英雄单位，并为其设置独特的属性和技能。学完本节后，你将能够创建一个可升级、拥有三维属性（力量/敏捷/智力）的完整英雄角色。</p><h3 id="操作步骤-2" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-2" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>创建单位并设为英雄</strong> — 在对象编辑器（Object Editor）中，按 <code>Ctrl+Shift+N</code> 快捷键创建一个新单位[^1]。在单位属性中找到&quot;英雄（Hero）&quot;选项，将其设置为&quot;是（True）&quot;——这一步是把普通单位变成英雄的关键操作[^2]。</p></li><li><p><strong>设置英雄三维属性</strong> — 找到&quot;属性 - 英雄（Stats - Hero）&quot;栏目，分别设置以下三个数值：</p><ul><li><strong>力量（Strength）</strong>：影响生命值和生命恢复速度</li><li><strong>敏捷（Agility）</strong>：影响攻击速度和护甲</li><li><strong>智力（Intelligence）</strong>：影响魔法值和魔法恢复速度</li></ul></li><li><p><strong>设置初始属性值</strong> — 在&quot;主要属性（Primary Attribute）&quot;中选择你的英雄类型，这将决定每级升级时属性成长的奖励加成方向。</p></li><li><p><strong>添加英雄技能</strong> — 切换到技能（Abilities）标签页，点击&quot;+&quot;按钮添加技能。从技能列表中选择你想让英雄学习的技能（最多4个主动技能）[^3]。</p></li><li><p><strong>设置头像和图标</strong> — 在&quot;Art - Icon - Game Interface&quot;字段中设置英雄的头像图片，这个图标会在选择英雄时显示[^2]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：英雄单位必须有头像才能在游戏中正常显示！如果看不到英雄的头像，首先检查这个字段是否为空。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手常忘记给英雄添加&quot;休息（Rest）&quot;或&quot;复活（Revive）&quot;技能，这会导致英雄死亡后无法复活。请在技能列表中找到这些技能并添加。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你的英雄单位应该已经具备了：</p><ul><li>英雄身份标识（可在战场上升级）</li><li>完整的三维属性配置</li><li>可使用的技能栏位</li></ul><p>你可以把这名英雄拖放到地图的初始位置进行测试。按F6打开触发器编辑器，测试英雄升级和技能释放是否正常工作。</p><h2 id="为单位添加技能" tabindex="-1">为单位添加技能 <a class="header-anchor" href="#为单位添加技能" aria-label="Permalink to “为单位添加技能”">​</a></h2><p>在本节中，你将学习如何为你的自定义单位添加技能（也叫&quot;魔法&quot;或&quot;技能&quot;）。学完之后，你的英雄或士兵就能使用各种攻击技能、治疗技能或其他特殊能力了！</p><h3 id="操作步骤-3" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-3" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>打开单位编辑器并选中你的单位</strong> — 首先，在左侧的&quot;单位&quot;面板中找到你之前创建的自定义单位，双击它打开单位属性窗口[^1]</p></li><li><p><strong>切换到&quot;技能-英雄&quot;或&quot;技能-普通&quot;选项卡</strong> — 在单位属性窗口中，你会看到多个选项卡。如果是英雄单位，点击&quot;技能-英雄&quot;；如果是普通士兵，点击&quot;技能-普通&quot;[^1]</p></li><li><p><strong>从技能库添加技能</strong> — 点击&quot;+&quot;按钮，会弹出技能选择窗口。这里列出了所有内置技能，包括攻击光环、治疗法术等。选择你想要的技能后点击&quot;确定&quot;[^1]</p></li><li><p><strong>设置技能等级</strong> — 添加技能后，你可以看到它默认是1级。如果想让它更强，可以修改等级数值（最高6级）[^2]</p></li><li><p><strong>设置冷却时间（可选）</strong> — 如果需要调整技能的冷却时间，选中该技能后找到&quot;数据 - 冷却时间&quot;字段进行修改[^2]</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：给单位添加多个技能时，记得考虑技能栏的位置。如果你的英雄有5个技能，确保它们分布在不同的技能栏格子里。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记英雄的技能需要先在&quot;技能-英雄&quot;选项卡中添加，而普通单位的技能要加到&quot;技能-普通&quot;选项卡。加错地方会导致技能无法正常使用。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能看到你的单位拥有了一个或多个技能。按F6打开测试地图，按住鼠标左键拖动你的单位到战场上，按数字键1-6测试各个技能是否正常工作！如果技能没有出现，检查一下是否添加到了正确的选项卡中。</p><h2 id="测试与常见问题" tabindex="-1">测试与常见问题 <a class="header-anchor" href="#测试与常见问题" aria-label="Permalink to “测试与常见问题”">​</a></h2><p>本节将学习如何测试你创建的自定义单位，以及当单位出现问题时的快速解决方法。完成本节后，你将能够独立验证单位是否正常工作，并解决常见的显示和属性问题。</p><h3 id="如何在地图中测试自定义单位" tabindex="-1">如何在地图中测试自定义单位 <a class="header-anchor" href="#如何在地图中测试自定义单位" aria-label="Permalink to “如何在地图中测试自定义单位”">​</a></h3><ol><li><p><strong>保存你的地图</strong> — 在世界编辑器中，按 <code>Ctrl + S</code> 保存当前工作[^1]。这一步非常重要！未保存的更改不会出现在测试中。</p></li><li><p><strong>打开测试模式</strong> — 点击编辑器顶部的绿色&quot;开始游戏&quot;按钮（像一个播放符号▶），或直接按 <code>F10</code>[^3]。世界编辑器会启动 Warcraft III 游戏，并自动加载你的地图。</p></li><li><p><strong>找到你的单位</strong> — 使用 <code>Ctrl + 点击</code> 选中你创建的自定义单位（单位会出现在屏幕中央的&quot;游戏内编辑器&quot;中）[^1]。如果是英雄单位，它应该在玩家1的基地附近。</p></li><li><p><strong>观察单位属性</strong> — 把鼠标悬停在单位上，查看它的生命值、攻击力、移动速度等属性是否与你设置的一致[^2]。特别注意&quot;Combat - Attack 1 - Damage&quot;（攻击伤害）和&quot;Movement - Speed&quot;（移动速度）字段。</p></li><li><p><strong>测试单位功能</strong> — 让单位攻击一个敌人，或者尝试使用英雄的技能。如果一切正常，说明你的设置生效了。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手忘记保存地图就急着测试，结果发现单位根本没有变化。<strong>一定要记住按 Ctrl+S 保存！</strong></p></blockquote><blockquote><p><strong>💡 新手提示</strong>：测试时建议打开&quot;作弊&quot;功能（在聊天框输入 -levels on），这样可以快速升级英雄，更好地测试技能和属性成长。</p></blockquote><h3 id="单位不显示-属性不生效的解决方法" tabindex="-1">单位不显示/属性不生效的解决方法 <a class="header-anchor" href="#单位不显示-属性不生效的解决方法" aria-label="Permalink to “单位不显示/属性不生效的解决方法”">​</a></h3><p><strong>问题一：单位在地图上完全不显示</strong></p><p>这种情况通常是因为单位没有被正确放置或分配给玩家。</p><ol><li>检查单位是否在&quot;对象管理器&quot;（Object Manager）中存在[^1]</li><li>确认你把单位拖放到了地图的&quot;可玩区域&quot;内（不是黑色边框外）</li><li>检查&quot;玩家属性&quot;——确保单位分配给的玩家颜色是&quot;可用的&quot;（比如玩家1-红色）</li></ol><p><strong>问题二：单位的图标或模型显示为问号&quot;？&quot;</strong></p><p>这是因为模型或头像文件路径错误。</p><ol><li>在单位数据中，找到&quot;Art - Model&quot;字段[^2]</li><li>确认路径是&quot;units\\human\\Footman.mdx&quot;这样的格式，不要缺少反斜杠</li><li>如果你不确定路径，可以点击字段右侧的&quot;...&quot;按钮，从列表中选择</li></ol><p><strong>问题三：属性数值没有生效</strong></p><p>有时你改了攻击伤害，但实际战斗中数值不变。</p><ol><li>确认你修改的是正确的字段（Attack 1 或 Attack 2）[^2]</li><li>检查是否有触发器（Trigger）覆盖了你的属性设置</li><li>重启世界编辑器再测试——有时候编辑器需要刷新</li></ol><blockquote><p><strong>💡 新手提示</strong>：养成&quot;小步测试&quot;的习惯。每修改一个属性，就保存并测试一次。这样你能快速定位是哪一步出了问题。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：修改了数据却发现没效果，很可能是同时打开了多个世界编辑器窗口，旧窗口的数据覆盖了新窗口的保存。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够：</p><ul><li>✅ 使用世界编辑器的测试功能运行地图</li><li>✅ 在游戏中验证自定义单位的外观和属性</li><li>✅ 诊断并解决单位不显示的常见原因</li><li>✅ 修复属性不生效的技术问题</li></ul><p>如果问题仍然存在，建议查看完整的控制台日志（点击&quot;测试模式&quot;菜单 → &quot;显示调试日志&quot;），那里会显示具体的错误信息，帮助你进一步排查。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/threads/creating-custom-units.270941/" target="_blank" rel="noreferrer">[General] - Creating Custom Units - Hive Workshop</a> — accessed 2026-04-28 [^2]: <a href="https://www.thehelper.net/threads/the-basics-of-the-world-editor.33390/" target="_blank" rel="noreferrer">Tutorial - The Basics of the World Editor | The Helper</a> — accessed 2026-04-28 [^3]: <a href="https://www.youtube.com/watch?v=kH0vKi0_WDU" target="_blank" rel="noreferrer">WC3 World Editor Creating Custom Units</a> — accessed 2026-04-28</p>',73)])])}const d=o(l,[["render",i]]);export{c as __pageData,d as default};
